/**
 * Order validators — pure validation functions for order-related inputs.
 *
 * No side effects, no database calls. Reusable across services.
 */

import type { CreateOrderInput, OrderStatus } from '../models/order.js';

/**
 * Valid order status transitions.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate a status transition, throwing if invalid.
 */
export function validateOrderStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * Validate input for creating an order.
 * Checks that the order has at least one item.
 */
export function validateCreateOrderInput(input: CreateOrderInput): void {
  if (input.items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * User validators — pure validation functions for user-related inputs.
 *
 * No side effects, no database calls. Reusable across services.
 */

import type { CreateUserInput, UpdateUserInput } from '../models/user.js';

/**
 * Validate input for creating a user.
 * Checks that name and email are non-empty strings.
 */
export function validateCreateUserInput(input: CreateUserInput): void {
  if (!input.name || input.name.trim().length === 0) {
    throw new Error('User name is required');
  }

  if (!input.email || input.email.trim().length === 0) {
    throw new Error('User email is required');
  }

  validateEmailFormat(input.email);
}

/**
 * Validate input for updating a user.
 * Checks that provided fields have valid values.
 */
export function validateUpdateUserInput(input: UpdateUserInput): void {
  if (input.name !== undefined && input.name.trim().length === 0) {
    throw new Error('User name cannot be empty');
  }

  if (input.email !== undefined) {
    if (input.email.trim().length === 0) {
      throw new Error('User email cannot be empty');
    }
    validateEmailFormat(input.email);
  }
}

/**
 * Validate that an email address has a basic valid format.
 */
export function validateEmailFormat(email: string): void {
  if (!email.includes('@')) {
    throw new Error(`Invalid email format: ${email}`);
  }
}

/**
 * Preferences validators — pure validation functions for preference-related inputs.
 *
 * No side effects, no database calls. Reusable across services.
 */

import type { CreatePreferencesInput, UpdatePreferencesInput, EmailFrequency } from '../models/user-preferences.js';

const VALID_FREQUENCIES: EmailFrequency[] = ['immediate', 'daily-digest', 'weekly-digest'];

/**
 * Validate input for creating user preferences.
 * Checks that userId is provided and email settings are valid if present.
 */
export function validateCreatePreferencesInput(input: CreatePreferencesInput): void {
  if (!input.userId || input.userId.trim().length === 0) {
    throw new Error('User ID is required for preferences');
  }

  if (input.email) {
    validateEmailPreferencesInput(input.email);
  }
}

/**
 * Validate input for updating user preferences.
 * Checks that email settings are valid if present.
 */
export function validateUpdatePreferencesInput(input: UpdatePreferencesInput): void {
  if (input.email) {
    validateEmailPreferencesInput(input.email);
  }
}

/**
 * Validate email preferences input fields.
 */
function validateEmailPreferencesInput(input: { frequency?: EmailFrequency }): void {
  if (input.frequency !== undefined && !VALID_FREQUENCIES.includes(input.frequency)) {
    throw new Error(`Invalid email frequency: ${input.frequency}`);
  }
}

