import { describe, it, expect } from 'vitest';
import {
  isValidStatusTransition,
  validateOrderStatusTransition,
  validateCreateOrderInput,
} from '../../src/validators/order.validator.js';

describe('Order Validators', () => {
  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
    });
  });

  describe('validateOrderStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateOrderStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateOrderStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });
  });

  describe('validateCreateOrderInput', () => {
    it('should not throw for valid input with items', () => {
      expect(() =>
        validateCreateOrderInput({
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
        }),
      ).not.toThrow();
    });

    it('should throw for empty items array', () => {
      expect(() =>
        validateCreateOrderInput({ userId: 'user-1', items: [] }),
      ).toThrow('Order must have at least one item');
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateCreateUserInput,
  validateUpdateUserInput,
  validateEmailFormat,
} from '../../src/validators/user.validator.js';

describe('User Validators', () => {
  describe('validateCreateUserInput', () => {
    it('should not throw for valid input', () => {
      expect(() =>
        validateCreateUserInput({
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
        }),
      ).not.toThrow();
    });

    it('should throw for empty name', () => {
      expect(() =>
        validateCreateUserInput({
          name: '',
          email: 'alice@example.com',
          role: 'member',
        }),
      ).toThrow('User name is required');
    });

    it('should throw for whitespace-only name', () => {
      expect(() =>
        validateCreateUserInput({
          name: '   ',
          email: 'alice@example.com',
          role: 'member',
        }),
      ).toThrow('User name is required');
    });

    it('should throw for empty email', () => {
      expect(() =>
        validateCreateUserInput({
          name: 'Alice',
          email: '',
          role: 'member',
        }),
      ).toThrow('User email is required');
    });

    it('should throw for invalid email format', () => {
      expect(() =>
        validateCreateUserInput({
          name: 'Alice',
          email: 'not-an-email',
          role: 'member',
        }),
      ).toThrow('Invalid email format');
    });
  });

  describe('validateUpdateUserInput', () => {
    it('should not throw for valid partial input', () => {
      expect(() => validateUpdateUserInput({ name: 'Bob' })).not.toThrow();
    });

    it('should not throw for empty object', () => {
      expect(() => validateUpdateUserInput({})).not.toThrow();
    });

    it('should throw for empty name', () => {
      expect(() => validateUpdateUserInput({ name: '' })).toThrow(
        'User name cannot be empty',
      );
    });

    it('should throw for empty email', () => {
      expect(() => validateUpdateUserInput({ email: '' })).toThrow(
        'User email cannot be empty',
      );
    });

    it('should throw for invalid email format on update', () => {
      expect(() => validateUpdateUserInput({ email: 'bad-email' })).toThrow(
        'Invalid email format',
      );
    });

    it('should accept valid email on update', () => {
      expect(() =>
        validateUpdateUserInput({ email: 'bob@example.com' }),
      ).not.toThrow();
    });
  });

  describe('validateEmailFormat', () => {
    it('should accept valid email', () => {
      expect(() => validateEmailFormat('user@example.com')).not.toThrow();
    });

    it('should reject email without @', () => {
      expect(() => validateEmailFormat('userexample.com')).toThrow(
        'Invalid email format',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateCreatePreferencesInput,
  validateUpdatePreferencesInput,
} from '../../src/validators/preferences.validator.js';

describe('Preferences Validators', () => {
  describe('validateCreatePreferencesInput', () => {
    it('should not throw for valid input', () => {
      expect(() =>
        validateCreatePreferencesInput({ userId: 'user-1' }),
      ).not.toThrow();
    });

    it('should not throw for input with email preferences', () => {
      expect(() =>
        validateCreatePreferencesInput({
          userId: 'user-1',
          email: { enabled: true, frequency: 'immediate' },
        }),
      ).not.toThrow();
    });

    it('should throw for empty userId', () => {
      expect(() =>
        validateCreatePreferencesInput({ userId: '' }),
      ).toThrow('User ID is required for preferences');
    });

    it('should throw for whitespace-only userId', () => {
      expect(() =>
        validateCreatePreferencesInput({ userId: '   ' }),
      ).toThrow('User ID is required for preferences');
    });
  });

  describe('validateUpdatePreferencesInput', () => {
    it('should not throw for empty input', () => {
      expect(() => validateUpdatePreferencesInput({})).not.toThrow();
    });

    it('should not throw for valid email preferences', () => {
      expect(() =>
        validateUpdatePreferencesInput({
          email: { frequency: 'daily-digest' },
        }),
      ).not.toThrow();
    });

    it('should not throw for valid weekly-digest frequency', () => {
      expect(() =>
        validateUpdatePreferencesInput({
          email: { frequency: 'weekly-digest' },
        }),
      ).not.toThrow();
    });
  });
});

